from datetime import date, timedelta
from collections import defaultdict

def compute_cohort_retention(
    activations: dict[str, date],    # user_id -> activation_date
    daily_active_users: dict[date, set[str]],  # date -> set of active user_ids
    cohort_month: str,               # e.g. "2025-01"
) -> dict:
    """Compute D30/D60/D90 retention for users activated in cohort_month."""
    cohort_users = {
        uid for uid, act_date in activations.items()
        if act_date.strftime("%Y-%m") == cohort_month
    }
    if not cohort_users:
        return {"cohort": cohort_month, "error": "no users"}

    def retention_at_day(n: int) -> float:
        retained = 0
        for uid in cohort_users:
            activation = activations[uid]
            target_date = activation + timedelta(days=n)
            # User is retained if active on any day in a 7-day window around target
            for delta in range(-3, 4):
                check_date = target_date + timedelta(days=delta)
                if uid in daily_active_users.get(check_date, set()):
                    retained += 1
                    break
        return retained / len(cohort_users)

    return {
        "cohort": cohort_month,
        "cohort_size": len(cohort_users),
        "d30_retention": round(retention_at_day(30), 4),
        "d60_retention": round(retention_at_day(60), 4),
        "d90_retention": round(retention_at_day(90), 4),
    }

import httpx
from datetime import date

OKR_TARGETS = {
    "adoption_rate": 0.70,      # 70% WAU target
    "d30_retention": 0.60,      # 60% 30-day retention
    "avg_feature_depth": 3.0,   # 3+ distinct features per active user
}

def adoption_rag_status(metric_value: float, target: float) -> str:
    """Return Red/Amber/Green status string based on % of target achieved."""
    ratio = metric_value / target if target else 0
    if ratio >= 0.90:
        return "GREEN"
    if ratio >= 0.70:
        return "AMBER"
    return "RED"

def format_manager_digest(manager_name: str, team_metrics: dict) -> str:
    lines = [
        f"*AI Adoption Digest — week of {date.today().isoformat()}*",
        f"Team: {manager_name}
",
    ]
    for key, target in OKR_TARGETS.items():
        value = team_metrics.get(key, 0.0)
        status = adoption_rag_status(value, target)
        emoji = {"GREEN": ":large_green_circle:", "AMBER": ":large_yellow_circle:", "RED": ":red_circle:"}[status]
        lines.append(f"{emoji}  *{key}*: {value:.1%} (target {target:.0%})")

    if team_metrics.get("adoption_rate", 0) < OKR_TARGETS["adoption_rate"] * 0.70:
        lines.append(
            "
:bulb: *Recommended action*: Schedule a 30-minute hands-on session "
            "for team members who have not activated yet."
        )
    return "
".join(lines)

def send_slack_digest(webhook_url: str, manager_name: str, team_metrics: dict):
    text = format_manager_digest(manager_name, team_metrics)
    response = httpx.post(webhook_url, json={"text": text}, timeout=10)
    response.raise_for_status()

